lines = raw_data.split('\n')
print(f"Total lines: {len(lines)}")

decoded_payloads = []

for i, line in enumerate(lines):
    #print(f"Line {i}: {line[:50]}...")
    try:
        if '["wrb.fr"' in line:
            #print(f"  Found wrb.fr at line {i}")
            data = json.loads(line)
            #print(f"  Outer JSON loaded.")
            if len(data) > 2 and isinstance(data[2], str):
                inner_json = json.loads(data[2])
                decoded_payloads.append(inner_json)
                #print(f"  Inner JSON loaded.")
    except json.JSONDecodeError as e:
        #print(f"  JSON Decode Error at line {i}: {e}")
        pass
    except Exception as e:
        #print(f"  Error at line {i}: {e}")
        pass

#print(f"Decoded payloads count: {len(decoded_payloads)}")

final_text = ""
target_prefix = "The pivot to a Chrome extension"

def search_for_text(obj):
    if isinstance(obj, str):
        if target_prefix in obj:
            return obj
    elif isinstance(obj, list):
        for item in obj:
            res = search_for_text(item)
            if res: return res
    return None

for payload in decoded_payloads:
    found = search_for_text(payload)
    if found and len(found) > len(final_text):
        final_text = found

print("FINAL TEXT:")
print(final_text)
